1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: "quote"; items: Array<Item> };
11	type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Array<Step>;
14	};
15	
16	const itemPremium = (item: Item): number => {
17	  const base = BASE_PREMIUM[item.type];
18	  return base + base * FIRST_INSURANCE_RATE;
19	};
20	
21	const quotePremium = (step: Step): number => {
22	  const sum = step.items.reduce((acc, item) => acc + itemPremium(item), 0);
23	  return sum + PROCESSING_FEE;
24	};
25	
26	export const runScenario = (scenario: unknown): unknown => {
27	  const { steps } = scenario as Scenario;
28	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
29	  return { results };
30	};
